#!/usr/bin/env bash
# StreamVault v2 — Installer
# curl -fsSL https://raw.githubusercontent.com/ray0189/streamvault/main/install.sh -o /tmp/sv.sh && bash /tmp/sv.sh
set -euo pipefail
R='\033[0;31m' G='\033[0;32m' Y='\033[1;33m' C='\033[0;36m' W='\033[1;37m' DIM='\033[2m' BOLD='\033[1m' NC='\033[0m'
ok()   { echo -e "  ${G}✓${NC} $*"; }
warn() { echo -e "  ${Y}⚠${NC}  $*"; }
err()  { echo -e "\n  ${R}✗ $*${NC}\n"; exit 1; }
sep()  { echo -e "\n  ${DIM}──────────────────────────────────────────${NC}"; }
hdr()  { echo -e "\n  ${BOLD}${C}$*${NC}"; }
lc()   { echo "$1" | tr '[:upper:]' '[:lower:]'; }
INSTALL_DIR="$HOME/streamvault"
SVC="streamvault"
CLI_BIN="/usr/local/bin/streamvault"
SUDO=""; [[ $EUID -ne 0 ]] && SUDO="sudo"
clear || true
echo -e "\n${C}${BOLD}  ╔══════════════════════════════════════════╗${NC}"
echo -e "${C}${BOLD}  ║      StreamVault  v2  —  Installer       ║${NC}"
echo -e "${C}${BOLD}  ║  Private TorBox · CLI-first · Zero ports ║${NC}"
echo -e "${C}${BOLD}  ╚══════════════════════════════════════════╝${NC}\n"

# ── OS ────────────────────────────────────────────────────────
hdr "System Detection"; sep
OS="$(uname -s)"; ARCH="$(uname -m)"
IS_MAC=false; IS_WSL=false; IS_LINUX=false
case "$OS" in
  Darwin) IS_MAC=true;  ok "macOS ($ARCH)" ;;
  Linux)  IS_LINUX=true; grep -qi microsoft /proc/version 2>/dev/null && IS_WSL=true
          $IS_WSL && ok "WSL ($ARCH)" || ok "Linux ($ARCH)" ;;
  *) err "Unsupported OS: $OS" ;;
esac
if $IS_MAC && ! command -v brew &>/dev/null; then
  echo -e "  ${DIM}Installing Homebrew…${NC}"
  /bin/bash -c "$(curl -fsSL https://raw.githubusercontent.com/Homebrew/install/HEAD/install.sh)"
  eval "$(/opt/homebrew/bin/brew shellenv)" 2>/dev/null || eval "$(/usr/local/bin/brew shellenv)" 2>/dev/null || true
fi
for cmd in curl git python3; do
  command -v "$cmd" &>/dev/null && ok "$cmd" || { $IS_MAC && brew install "$cmd" >/dev/null 2>&1 && ok "$cmd" || err "$cmd required"; }
done

# ── Node.js ───────────────────────────────────────────────────
hdr "Node.js"; sep
NODE_OK=false
command -v node &>/dev/null && node -e "process.exit(parseInt(process.version.slice(1))<18?1:0)" 2>/dev/null && NODE_OK=true || true
if $NODE_OK; then ok "Node.js $(node --version)"
else
  echo -e "  ${DIM}Installing Node.js v22…${NC}"
  if $IS_MAC; then
    brew install node@22 >/dev/null 2>&1 && brew link node@22 --force --overwrite >/dev/null 2>&1 || brew install node >/dev/null 2>&1
    export PATH="/opt/homebrew/opt/node@22/bin:/usr/local/opt/node@22/bin:$PATH"
  else
    curl -fsSL https://deb.nodesource.com/setup_22.x | $SUDO bash - >/dev/null 2>&1
    $SUDO apt-get install -y nodejs >/dev/null 2>&1
  fi
  ok "Node.js $(node --version)"
fi

# ── Redis ─────────────────────────────────────────────────────
hdr "Redis"; sep
REDIS_OK=false
command -v redis-cli &>/dev/null && redis-cli ping 2>/dev/null | grep -q PONG && REDIS_OK=true || true
if $REDIS_OK; then ok "Redis running"
elif command -v docker &>/dev/null && docker ps 2>/dev/null | grep -q redis; then ok "Redis (Docker)"
elif $IS_MAC; then brew install redis >/dev/null 2>&1; brew services start redis >/dev/null 2>&1; sleep 1 && ok "Redis (Homebrew)"
elif command -v docker &>/dev/null; then
  docker run -d --name sv-redis --restart always -p 6379:6379 redis:7-alpine >/dev/null 2>&1 && ok "Redis (Docker)"
else
  $SUDO apt-get install -y redis-server >/dev/null 2>&1
  $SUDO systemctl enable --now redis-server >/dev/null 2>&1 || true; ok "Redis installed"
fi

# ── Source files ──────────────────────────────────────────────
hdr "Writing source files"; sep
mkdir -p "$INSTALL_DIR"/{src/{addon,api,cache,config,filters,profiles,scoring},data,logs,bin,backups}
python3 << 'PY_FILES'
import os, base64
D = os.path.expanduser('~/streamvault')
F = {
  'src/config/env.js': '',
  'src/config/defaults.js': '',
  'src/cache/store.js': '',
  'src/filters/quality.js': '',
  'src/scoring/rank.js': '',
  'src/profiles/store.js': '',
  'src/api/torbox.js': '',
  'src/addon/manifest.js': '',
  'src/addon/router.js': '',
  'src/addon/streams.js': '',
  'src/api/router.js': '',
  'src/server.js': '',
  'package.json': '',
  '.gitignore': 'LmVudgpkYXRhLwpub2RlX21vZHVsZXMvCmxvZ3MvCioubG9nCi5EU19TdG9yZQoqLnRhci5neg==',
  '.env.example': '',
}

for rel, enc in F.items():
    fp = os.path.join(D, rel)
    os.makedirs(os.path.dirname(fp), exist_ok=True)
    with open(fp, 'w') as f:
        f.write(base64.b64decode(enc).decode())
print('  ✓ Source files written (' + str(len(F)) + ' files)')

PY_FILES

python3 -c "
import os,base64
cli=base64.b64decode('').decode()
fp=os.path.expanduser('~/streamvault/bin/streamvault')
os.makedirs(os.path.dirname(fp),exist_ok=True)
open(fp,'w').write(cli)
os.chmod(fp,0o755)
"

# package.json
python3 -c "
import os,json
p={'name':'streamvault','version':'2.0.0','description':'Private TorBox Stremio addon',
'main':'src/server.js','scripts':{'start':'node src/server.js','dev':'nodemon src/server.js'},
'bin':{'streamvault':'./bin/streamvault'},
'dependencies':{'axios':'^1.6.0','compression':'^1.7.4','cors':'^2.8.5','dotenv':'^16.3.1',
'express':'^4.18.2','express-rate-limit':'^7.1.5','form-data':'^4.0.0',
'ioredis':'^5.3.2','node-cache':'^5.1.2','uuid':'^9.0.0'},
'devDependencies':{'nodemon':'^3.0.1'}}
open(os.path.expanduser('~/streamvault/package.json'),'w').write(__import__('json').dumps(p,indent=2))
"
echo '.env
data/
node_modules/
logs/
backups/
*.log
.DS_Store' > "$INSTALL_DIR/.gitignore"
ok "Source files written"

# ── npm install ───────────────────────────────────────────────
hdr "Installing dependencies"; sep
cd "$INSTALL_DIR"
npm install --no-fund --no-audit --silent
ok "$(ls node_modules | wc -l | tr -d ' ') packages installed"

# ── Global CLI ────────────────────────────────────────────────
hdr "Installing CLI"; sep
$SUDO ln -sf "$INSTALL_DIR/bin/streamvault" "$CLI_BIN"
$SUDO chmod +x "$CLI_BIN"
ok "streamvault CLI available globally"

# ── cloudflared ───────────────────────────────────────────────
hdr "Cloudflare Tunnel"; sep
if ! command -v cloudflared &>/dev/null; then
  echo -e "  ${DIM}Installing cloudflared…${NC}"
  if $IS_MAC; then brew install cloudflared >/dev/null 2>&1
  elif [[ "$ARCH" == "aarch64" || "$ARCH" == "arm64" ]]; then
    curl -fsSL https://github.com/cloudflare/cloudflared/releases/latest/download/cloudflared-linux-arm64 -o /tmp/cf
    $SUDO install /tmp/cf /usr/local/bin/cloudflared
  else
    curl -fsSL https://pkg.cloudflare.com/cloudflare-main.gpg | $SUDO tee /usr/share/keyrings/cloudflare-main.gpg >/dev/null
    echo "deb [signed-by=/usr/share/keyrings/cloudflare-main.gpg] https://pkg.cloudflare.com/cloudflared any main" | $SUDO tee /etc/apt/sources.list.d/cloudflared.list >/dev/null
    $SUDO apt-get update -qq >/dev/null 2>&1 && $SUDO apt-get install -y cloudflared >/dev/null 2>&1
  fi
  ok "cloudflared installed"
else
  ok "cloudflared already installed"
fi

# ── System service ────────────────────────────────────────────
hdr "System service"; sep
NODE_BIN=$(command -v node)

if $IS_MAC; then
  python3 -c "
import os,base64
py=base64.b64decode('').decode()
exec(py)
"
  launchctl unload "$HOME/Library/LaunchAgents/com.streamvault.plist" 2>/dev/null || true
  launchctl load -w "$HOME/Library/LaunchAgents/com.streamvault.plist"
  sleep 2
  curl -sf "http://localhost:7000/health" >/dev/null && ok "Service started (launchd)" || warn "Check: tail -f $INSTALL_DIR/logs/sv.log"
elif $IS_LINUX; then

  $SUDO tee /etc/systemd/system/${SVC}.service >/dev/null << SVCEOF
[Unit]
Description=StreamVault v2 — Private TorBox Stremio Addon
After=network.target
Wants=network.target
[Service]
Type=simple
User=$USER
WorkingDirectory=${INSTALL_DIR}
ExecStart=${NODE_BIN} src/server.js
Restart=always
RestartSec=5
StartLimitInterval=60
StartLimitBurst=5
EnvironmentFile=${INSTALL_DIR}/.env
StandardOutput=append:/var/log/streamvault.log
StandardError=append:/var/log/streamvault.log
[Install]
WantedBy=multi-user.target
SVCEOF
  $SUDO systemctl daemon-reload
  $SUDO systemctl enable "${SVC}" >/dev/null 2>&1
  ok "systemd service installed"
fi

# ── Setup wizard ──────────────────────────────────────────────
hdr "Configuration"; sep
echo ""
node "$INSTALL_DIR/bin/streamvault" setup

# ── Start ─────────────────────────────────────────────────────
if $IS_LINUX && ! $IS_WSL; then
  $SUDO systemctl start "${SVC}" 2>/dev/null || true
  sleep 3
  $SUDO systemctl is-active --quiet "${SVC}" && ok "StreamVault running" || warn "Check: streamvault logs"
fi

# ── Done ──────────────────────────────────────────────────────
sep
echo -e "\n  ${G}${BOLD}✓ StreamVault v2 installed${NC}\n"
echo -e "  ${C}streamvault profile add${NC}    — create first profile"
echo -e "  ${C}streamvault profile list${NC}   — get manifest URLs"
echo -e "  ${C}streamvault status${NC}         — health check"
echo -e "  ${C}streamvault help${NC}           — all commands\n"
